#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)
#define BLOCK_SIZE (256)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func_cpu(T seed, T *data, size_t total_elements, int num_threads){
	const int stride = BLOCK_SIZE;
	const size_t total_work = total_elements / sizeof(T);
	const size_t per_thread = total_work / num_threads;

	#pragma omp parallel for
	for(int t=0; t<num_threads; t++){
		size_t idx = t * per_thread;
		size_t thread_end = (t == num_threads-1) ? total_work : (t+1) * per_thread;

		T tmps[granularity];
		for(size_t k=0; k<fusion_degree; k++){
			for(size_t j=0; j<granularity; j++){
				size_t access_idx = idx + j*stride + k*total_work;
				if(access_idx < total_work){
					tmps[j] = data[access_idx];

					for(unsigned int i=0; i<compute_iterations; i++){
						tmps[j] = mad(tmps[j], tmps[j], seed);
					}
				}
			}

			T sum = conv_int<T>(0);
			for(size_t j=0; j<granularity; j+=2){
				if(j+1 < granularity){
					sum = mad(tmps[j], tmps[j+1], sum);
				}
			}

			if(equal(sum, conv_int<T>(-1))){
				size_t store_idx = idx + k*total_work;
				if(store_idx < total_work){
					data[store_idx] = sum;
				}
			}
		}
	}
}

double get_time_ms(){
	auto now = std::chrono::high_resolution_clock::now();
	auto ms = std::chrono::duration<double, std::milli>(now.time_since_epoch()).count();
	return ms;
}

void runbench_warmup_cpu(double *cd, size_t size){
	const size_t reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
	const int TOTAL_REDUCED_BLOCKS = reduced_grid_size/BLOCK_SIZE;
	const int num_threads = omp_get_max_threads();

	benchmark_func_cpu< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >(1, (short*)cd, size, num_threads);
}

int out_config = 1;

template<unsigned int compute_iterations>
void runbench_cpu(double *cd, size_t size, bool doHalfs){
	const size_t compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
	const int TOTAL_BLOCKS = compute_grid_size/BLOCK_SIZE;
	const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
	const long long memoryoperations = size;
	const int num_threads = omp_get_max_threads();

	double start_time, end_time;
	double kernel_time_mad_sp, kernel_time_mad_dp, kernel_time_mad_hp, kernel_time_mad_int;

	start_time = omp_get_wtime();
	benchmark_func_cpu< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, size, num_threads);
	end_time = omp_get_wtime();
	kernel_time_mad_sp = (end_time - start_time) * 1000.0;

	start_time = omp_get_wtime();
	benchmark_func_cpu< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0, cd, size, num_threads);
	end_time = omp_get_wtime();
	kernel_time_mad_dp = (end_time - start_time) * 1000.0;

	kernel_time_mad_hp = 0.0;
	if(doHalfs){
		start_time = omp_get_wtime();
		benchmark_func_cpu< uint16_t, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(15360, (uint16_t*)cd, size, num_threads);
		end_time = omp_get_wtime();
		kernel_time_mad_hp = (end_time - start_time) * 1000.0;
	}

	start_time = omp_get_wtime();
	benchmark_func_cpu< int, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true >(1, (int*)cd, size, num_threads);
	end_time = omp_get_wtime();
	kernel_time_mad_int = (end_time - start_time) * 1000.0;

	printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
		compute_iterations,
		((double)computations)/((double)memoryoperations*sizeof(float)),
		kernel_time_mad_sp,
		((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
		((double)computations)/((double)memoryoperations*sizeof(double)),
		kernel_time_mad_dp,
		((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
		((double)2*computations)/((double)memoryoperations*sizeof(uint16_t)),
		kernel_time_mad_hp,
		((double)2*computations)/kernel_time_mad_hp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(uint16_t))/kernel_time_mad_hp*1000./(1000.*1000.*1000.),
		((double)computations)/((double)memoryoperations*sizeof(int)),
		kernel_time_mad_int,
		((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

